// Extract leads array from API response
const response = $input.item.json;
const searchDate = $('Define Target ICP').item.json.searchDate;

// Handle different response structures
let leads = [];

if (response.result && Array.isArray(response.result)) {
  leads = response.result;
} else if (response.leads && Array.isArray(response.leads)) {
  leads = response.leads;
} else if (Array.isArray(response)) {
  leads = response;
}

// Return each lead as separate item for processing
return leads.map(lead => ({
  json: {
    fullName: lead.fullName || lead.name || '',
    email: lead.email || '',
    jobTitle: lead.jobTitle || lead.title || '',
    companyName: lead.companyName || lead.company || '',
    linkedinUrl: lead.linkedinUrl || lead.linkedin || '',
    searchDate: searchDate
  }
}));
